INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68027ae0e3c98b09417658fd', '房间卫生干净，服务很好，原来房间有一些小瑕疵，直接帮我们免费升级了房间，就是酒店比较老旧，周边交通很方便，地铁口就在酒店门口，酒店环境也非常好，早餐也可以', '["https://dimg04.c-ctrip.com/images/0234312000f7hcczb307F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232812000f7hjtmk8ABA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234k12000f7het3k368F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-08-22', '花园双床房', '双床房', '家庭亲子', 77, 0, 16, 7, '["卫生状况","前台服务","交通便利性"]'::jsonb, '卫生状况', '前台服务', '交通便利性'),
('68027ae0e3c98b09417658fe', '十分满意～', '["https://dimg04.c-ctrip.com/images/0235j12000hj2vvd88CB9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232i12000hj2ymlj1360_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231w12000hj2cyzbB5F9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-01', '花园大床房', '大床房', '其他', 5, 0, 10, 2, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027ae0e3c98b09417658ff', '看了各个平台的评论加上有岭南金的会员卡才来订的酒店，但入住感觉很一般。入住时报了金卡会员号，前台没有任何关于金卡会员的介绍。客房没升级、免费早餐也不提、酒廊礼遇还是在我特意询问后才给了一张一个人的礼遇卡。什么欢迎水果，入住三天毛都没看见。我也是开了眼了！
但是酒店装潢很漂亮，公共设施维护很好。只是客房卫生间反味，房型过于紧凑。给娃买了毛绒纪念品，小姐姐得知我们不用开发票直接给我个人微信二维码让我缴费……呵呵了……', '["https://dimg04.c-ctrip.com/images/0231412000esiy95p883E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231h12000esiv6lbB05C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232m12000esiyvbpCC4F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232a12000esip2ax13F8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.6, 3, '2024-07-15', '花园双床房', '双床房', '家庭亲子', 208, 1, 2, 9, '["前台服务","房间设施","整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度'),
('68027ae0e3c98b0941765900', '环境不错 但是价格有点高 里面有个博物馆 可以参观一下 总体还不错 缺点大堂没有休息的地方', '["https://dimg04.c-ctrip.com/images/0233d12000g22cdz1E57E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235112000g225hp56D78_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235j12000g224an25560_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2024-10-09', '花园双床房', '双床房', '家庭亲子', 45, 0, 4, 5, '["性价比","整体满意度","公共设施"]'::jsonb, '性价比', '整体满意度', '公共设施'),
('68027ae0e3c98b0941765901', '各区域的服务很细致
早餐出品不错
房间整体不错，舒适干净，唯独空调有噪音大，但还可接受。
泳池的设施设备也还行，但少了些泳衣泳裤甩干服务（虽然有塑料袋配）
FO Rebecca & Chef Ricky very nice
酒店内的博物馆不错值得看看', '["https://dimg04.c-ctrip.com/images/0232112000esbhvmm0DE0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234m12000esbmerh1FBA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234312000esbgrx8C860_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233q12000esbn2pq2542_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234i12000esbrh7p7E51_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-15', '花园大床房', '大床房', '朋友出游', 125, 0, 0, 7, '["整体满意度","餐饮设施","房间设施"]'::jsonb, '整体满意度', '餐饮设施', '房间设施'),
('68027ae0e3c98b0941765902', '金碧辉煌 园林幽雅', '["https://dimg04.c-ctrip.com/images/0232q12000hcmb4wu48E4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232512000hckwgzyABE3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234612000hclystm5673_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236g12000hcm5vdf7D72_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-12-22', '红棉双床套房', '套房', '其他', 9, 0, 35, 3, '["景观/朝向"]'::jsonb, '景观/朝向', NULL, NULL),
('68027ae0e3c98b0941765903', '酒店位置极佳，出门就是地铁，出行非常方便，酒店早餐的旋转餐厅也非常有特色，餐食丰富。酒店套餐中赠送的下午茶和欢乐时光，也很精致。', '["https://dimg04.c-ctrip.com/images/0231112000fmnlo8hBC98_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236y12000fmncqc3C5FC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230z12000fmnmvu9E4E8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-09-18', '花园双床房', '双床房', '情侣出游', 64, 0, 19, 8, '["交通便利性","餐饮设施","性价比"]'::jsonb, '交通便利性', '餐饮设施', '性价比'),
('68027aeae3c98b0941765904', '红棉双床房，房间很大，舒适，科技感十足，瀑布餐厅的自助早餐品种丰富，中西合璧，很是可口。携程上买的套餐，很划算。', '["https://dimg04.c-ctrip.com/images/0230j12000foas5zg5422_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235z12000foaott8C6A3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r12000foav5w11561_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231912000foaszsr9028_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-21', '红棉双床套房', '套房', '朋友出游', 56, 0, 3, 7, '["房间设施","餐饮设施","性价比"]'::jsonb, '房间设施', '餐饮设施', '性价比'),
('68027aeae3c98b0941765905', '非常棒，服务非常好??', '["https://dimg04.c-ctrip.com/images/0233t12000h9kmtig8183_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0233912000h9kqdwx2604_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2024-12-18', '花园双床房', '双床房', '商务出差', 11, 0, 11, 2, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027aeae3c98b0941765906', '花园酒店属罕见的城区花园式酒店，山水园林特别吸舒适，大堂辉煌有特色吸引眼球。借此机会还参观了博物馆了解酒店的历史底蕴。每到一处服务人员都很温柔礼貌，细心体贴。感谢酒店前台Gillian免费升级了红棉大房，还赠送了下午茶，如果房间能见到园林就更好了。下次还是会入住。', '["https://dimg04.c-ctrip.com/images/0234i12000es36dqeD570_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230912000es38e1iDB24_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230s12000es2zrep9E44_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231v12000es36mek2A8F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235q12000es35ndjC675_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232812000es341tx69BA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235d12000es36rfp2D1F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231f12000es33hq59620_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234i12000es37r6052DE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-14', '花园双床房', '双床房', '家庭亲子', 132, 1, 10, 9, '["整体满意度","前台服务","景观/朝向"]'::jsonb, '整体满意度', '前台服务', '景观/朝向'),
('68027aeae3c98b0941765907', '带父母和宝宝休假，房间无烟很安静，但空调口上方的墙壁发霉了没有清理。楼层房间的清洁阿姨和服务人员特别好。桃园馆的早茶的牛奶因为天气热了有点发酸，没有宝宝的餐具提供，而且有一个穿深蓝色西装的**男领班不会收餐盘，上水果时因为桌上有很多宝宝用过的纸巾和空盘子，当着客人的面很为难和不耐烦的叹气，好像不知道怎么处理似的，还需要我主动把一个空盘子递给他拿走才处理好，令人感觉很不舒服，服务意识和水平很低。服务细节需要提高培训。瀑布餐厅和荔湾亭的餐食和服务很满意，宝宝正在好动的年纪，但服务员对宝宝很有耐心，有很高的服务意识，餐食也很新鲜美味。前期打酒店电话预约时感觉接电话的服务人员和餐厅沟通协调不是很好，没有及时帮忙预约餐厅位置。到店后遇到的服务人员总体还不错。', '["https://dimg04.c-ctrip.com/images/0234d12000eudc7dz78F7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231l12000eudeojlE37A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236h12000eudlpjhB58D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-07-20', '花园双床房', '双床房', '家庭亲子', 328, 1, 18, 8, '["客房服务","餐饮设施","整体满意度"]'::jsonb, '客房服务', '餐饮设施', '整体满意度'),
('68027aeae3c98b0941765908', '带两个小孩 询问后给升级了房型 酒店很漂亮很高大上 早餐也很丰盛 各个服务员态度都很友善 笑脸相迎 很愉快的体验 有机会还是会选择这个酒店', '["https://dimg04.c-ctrip.com/images/0233u12000f9i3e1l8F60_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236c12000f9hp10v72A5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235y12000f9hkj6k9058_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000f9ia2aj2D20_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234012000f9hw9439CA1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-27', '花园大床房', '大床房', '家庭亲子', 69, 0, 2, 7, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('68027aeae3c98b0941765909', '好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好', '["https://dimg04.c-ctrip.com/images/0203h12000fl9iiu99657_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0204w12000fl9jpsg19AC_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0201z12000fl9itbd4AB5_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0230u12000fl8xbj64E67_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230b12000fl98iie1204_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231n12000fl94cl56CA6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-16', '花园大床房', '大床房', '独自旅行', 56, 0, 66, 0, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027aeae3c98b094176590a', '太满意了，性价比极高，服务巨好。体验感极佳，行政酒廊的小姐姐（名字如图）又漂亮又温柔，客房，硬件都非常优秀！住了2晚换了希尔顿，后悔中……', '["https://dimg04.c-ctrip.com/images/0236912000faf6zecE545_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233z12000faf6y0q1ED9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-28', '花园双床房', '双床房', '家庭亲子', 69, 0, 2, 8, '["性价比","整体满意度","前台服务"]'::jsonb, '性价比', '整体满意度', '前台服务'),
('68027aeae3c98b094176590b', '广州花园酒店，一家有着历史文化感的酒店，一家来了后会让你惊艳的酒店，一家需要专业讲解的酒店，一步一景，从金碧辉煌的大堂壁画到瀑布餐厅，后花园，到酒店自带的博物馆，都给人无限惊喜。床品很舒适，睡的很舒服，酒店服务很周到，给我们送了早餐和下午茶。特别感谢三十楼旋转餐厅的CARRIE和大堂的HENRY（带我们一路参观讲解酒店的历史文化景致，孩子很喜欢听）。总之，很值得入住的一家老牌酒店，适合亲子家庭出游入住，下次来还会选择。', '["https://dimg04.c-ctrip.com/images/0232h12000eqmxhqz46DB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x12000eqmxtym28BE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236m12000eqmxg1rBB08_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231i12000eqmxqgu99D4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233p12000eqmy7dvFBF2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230312000eqmxumnB71D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232312000eqmy7ge6D9F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-10', '花园大床房', '大床房', '家庭亲子', 211, 0, 5, 9, '["整体满意度","公共设施","前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务'),
('68027aeae3c98b094176590c', '偶然花园暑假推出特惠套餐，时隔几年再次带妹来打卡，非常惊喜，推出打卡点活动，参观酒店博物馆，晚上在荔湾亭任点任食茶点，早上望着瀑布品尝丰富早餐，一系列活动令行程丰富多彩，宝宝乐而忘返', '["https://dimg04.c-ctrip.com/images/0232w12000eupf8vxA8F5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234a12000eupd8y9013C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236s12000eupfw0q3E1B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-21', '花园双床房', '双床房', '家庭亲子', 91, 0, 16, 8, '["餐饮设施","整体满意度","公共设施"]'::jsonb, '餐饮设施', '整体满意度', '公共设施'),
('68027aeae3c98b094176590d', '服务我真的是想打超五星的评价，太贴心了，非常友好。
不过确实毕竟是老酒店，电话坏了我一直打不通联系不到前台，只能使用自己的手机，报姓名确认身份。
我们是带娃入住，说明之后准备了儿童拖鞋以及洗浴用品，非常感谢。离开的时候因为我们带娃涉及到睡午觉还给我们延迟退房到2:00。
总体我觉得是性价比很高～从入住到离开感受到了五星服务。', '["https://dimg04.c-ctrip.com/images/0232s12000eqmk4uq90D0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-10', '花园双床房', '双床房', '家庭亲子', 163, 0, 7, 8, '["前台服务","客房服务","性价比"]'::jsonb, '前台服务', '客房服务', '性价比'),
('68027af5e3c98b094176590e', '广州的老品牌高档酒店，商务出差，来到这里下榻。总体的感觉还是挺不错的，大堂富丽堂皇，房间干净清新，只是房内的设施稍显陈旧，客房大楼没有负一负二层，得到另外一个地下停车场停车，其他都挺好的。', '["https://dimg04.c-ctrip.com/images/0235012000esfoxpf02B0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234y12000esfoni2C76C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232w12000esfomcgB461_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-15', '花园大床房', '大床房', '商务出差', 94, 0, 48, 7, '["房间设施","整体满意度","卫生状况"]'::jsonb, '房间设施', '整体满意度', '卫生状况'),
('68027af5e3c98b094176590f', '房间插头很少，电视遥控极简模式很不方便操作。', '["https://dimg04.c-ctrip.com/images/0232w12000goccmhz5B9F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231l12000goccnli1E90_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2024-11-14', '红棉双床套房', '套房', '家庭亲子', 22, 0, 9, 6, '["房间设施"]'::jsonb, '房间设施', NULL, NULL),
('68027af5e3c98b0941765910', '非常满意的一次住宿体验，原本是为了酒店中的米其林餐厅来的，从到店接待的服务，每日清洁服务，多样化的早餐选择都让我重新认识了花园酒店，酒店自有的博物馆让我非常震撼。', '["https://dimg04.c-ctrip.com/images/0230s12000ezrabygC76F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230p12000ezrad62AD45_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231i12000ezrajup2BB4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231n12000ezrad719633_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000ezral512444_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233712000ezraph41628_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230412000ezral5mC5B8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233h12000ezrak2b0700_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235v12000ezraq2sEAAC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-03', '花园大床房', '大床房', '情侣出游', 81, 0, 16, 8, '["餐饮设施","前台服务","客房服务"]'::jsonb, '餐饮设施', '前台服务', '客房服务'),
('68027af5e3c98b0941765911', '带着父母入住，他们很满意，宾至如归。碰巧是我自己的生日，酒店给的情绪价值也是非常到位了，谢谢。
停车很方便。员工也很礼貌。', '["https://dimg04.c-ctrip.com/images/0230r12000feycrr694E9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235612000fey6eglA3A5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236212000fey6egn4926_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234712000feyjocbBA0F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236x12000fey5a6mE203_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-05', '红棉大床套房', '套房', '家庭亲子', 61, 0, 5, 6, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('68027af5e3c98b0941765912', '房间干净卫生，细节满满，还有文具盒。有??还提供浴盐，拖鞋很舒服。酒店内设计有博物馆很有特色。后花园很大很漂亮。赠送的小羊玩偶很可爱??', '["https://dimg04.c-ctrip.com/images/0230f12000f8xh0kw3C7E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230x12000f8xgtad254C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236c12000f8xn1gw1738_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236712000f8xgdwk141D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234k12000f8xkr0l2895_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233m12000f8xn11sE409_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236712000f8wz9kj3E07_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-25', '花园大床房', '大床房', '家庭亲子', 68, 0, 14, 7, '["房间设施","卫生状况","整体满意度"]'::jsonb, '房间设施', '卫生状况', '整体满意度'),
('68027af5e3c98b0941765913', '年味超浓~交通便利~后花园儿环境优美~下次来广州还住这里。
前台瑞贝卡特别nice，服务特别耐心细致~', '["https://dimg04.c-ctrip.com/images/0236q12000i5zc8n2215C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236o12000i5z9pvy68AA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237212000i5z54o1732A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237312000i5ybjmpDFEB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232n12000i5yaeaz6C5B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-30', '花园大床房', '大床房', '家庭亲子', 51, 0, 7, 7, '["整体满意度","交通便利性","前台服务"]'::jsonb, '整体满意度', '交通便利性', '前台服务'),
('68027af5e3c98b0941765914', '昨天交通很便利，门口就有地铁。服务非常周到，每层都有服务员。购买的套餐在楼顶的旋转餐厅吃早餐感觉很好。后面有一个很大的很美的花园。', '["https://dimg04.c-ctrip.com/images/0230b12000g2r8limD094_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236k12000g2r5qs046E3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233z12000g2rvqu3C73D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-10', '花园大床房', '大床房', '其他', 65, 0, 9, 7, '["交通便利性","餐饮设施","周边配套"]'::jsonb, '交通便利性', '餐饮设施', '周边配套'),
('68027af5e3c98b0941765915', '?? 广州花园酒店——一场无与伦比的入住体验 ??
 
朋友们，我刚从广州花园酒店回来，心情还沉浸在那无比美妙的时光里！必须要跟大家分享一下我这次超赞的入住经历！
 
当我踏入广州花园酒店的那一刻，就仿佛走进了一个充满魅力和故事的世界。酒店那悠久的历史气息扑面而来，每一处细节都仿佛在诉说着过去的辉煌，让我心生敬畏和好奇。
 
不得不提的是酒店的博物馆，这简直是一个隐藏的宝藏！在那里，我仿佛穿越了时空，领略到了酒店一路走来的风风雨雨，以及背后蕴含的深厚文化底蕴。那些珍贵的展品、精彩的介绍，让我对这座酒店有了更深层次的认识和理解。
 
而行政酒廊更是给我带来了惊喜不断！舒适优雅的环境，丰富多样的饮品和小吃，每一口都是极致的享受。在这里，我可以放松身心，尽情地享受属于自己的惬意时光。特别是主管carrie，美丽的印度小姐姐（周三还有来自尼泊尔的Kanchan小姐姐），提供了非常好的服务，happy hour的氛围很好，人也不多，顶楼可以看到广州老的CBD环市东的风景
 
但最让我感到温暖和满意的，还是酒店工作人员那无与伦比的热情态度。从进门的那一刻起，每一个微笑、每一句问候，都让我感受到了家一般的亲切。他们总是能在第一时间满足我的需求，无论是解答疑问还是提供帮助，都表现得专业而贴心。
 
还有酒店那美丽的花园！漫步其中，花香四溢，绿树成荫，仿佛置身于人间仙境。在这里，我可以暂时忘却外界的喧嚣和烦恼，尽情地享受大自然的恩赐。
 
总之，在广州花园酒店的这次入住体验，无论是硬件设施还是软件服务，都堪称完美。我真的非常喜欢这里，已经迫不及待地想要再次回来！强烈推荐给大家，相信你们也一定会爱上这个充满魅力的地方！', '["https://dimg04.c-ctrip.com/images/0233p12000eq7xlwm4875_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236h12000eq827m03F7E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234n12000eq8249fB2FE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-09', '花园大床房', '大床房', '独自旅行', 711, 0, 1, 9, '["整体满意度","前台服务","公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施'),
('68027af5e3c98b0941765916', '房间有点小，床品不错，还贴心地提供了荞麦枕。服务一如既往地好。', '["https://dimg04.c-ctrip.com/images/0232f12000gb6zjwhD03C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231f12000gb66npi1A30_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231t12000gb6t43c9B00_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-10-25', '城央绿意大床房', '大床房', '商务出差', 31, 0, 9, 6, '["房间设施","客房服务"]'::jsonb, '房间设施', '客房服务', NULL),
('68027af5e3c98b0941765917', '进门的香水味有点浓，外宾比较多，工作人员服务还不错，房间卫生也不错，隔音我觉得没有其他评价说的那么差，位置也方便，就是开窗需要工作人员来开比较麻烦。', '["https://dimg04.c-ctrip.com/images/0235o12000f3wiv4g3E88_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2024-08-13', '红棉双床套房', '套房', '家庭亲子', 74, 0, 4, 7, '["前台服务","卫生状况","安静程度"]'::jsonb, '前台服务', '卫生状况', '安静程度'),
('68027b02e3c98b0941765918', '感觉这酒店是给歪果仁开的
服务很一般（清扫服务员除外）
台灯坏了，打电话半天没人接，接了态度也不好，来人换灯进门不打招呼换完带有怨气的走了
硬件设施不错，估计这也是评上金榜的原因
但是房间一般，泳池一般，服务员高高在上。。。
瀑布餐厅更是可笑，明明他能去抢，但是他偏偏给你安排了一个外面摊位味道都不如的自助餐给你换钱', '["https://dimg04.c-ctrip.com/images/0232r12000eotj6cv1372_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2024-07-05', '花园双床房', '双床房', '家庭亲子', 158, 0, 3, 7, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('68027b02e3c98b0941765919', '花园酒店虽然经常光顾荔湾亭餐饮，住房还是头一次。酒店服务的确不错，无论进大堂门口，还是礼宾部，再进服务台前的礼仪小姐到服务台的登记，都是笑脸相迎，中途叫外卖在礼宾部那里收货，站开关门的小姐姐看到我行动不太方便主动帮忙提上客房，特别的感动。21楼兰英客房服务员每天不辞辛劳的打扫卫生，每每出去游玩回来之后，都有宾至如归的感觉。十天的旅游行程转眼就过去，到了退房时间，一大早21楼朱小姐的迎送、礼宾部刘先生帮忙把行李拿到礼宾部暂存，酒店无论是环境还是接待，都是一流的服务质量，下次有机会还是我首选的住宿地方。设施虽陈旧一点，其他都很好。', '["https://dimg04.c-ctrip.com/images/0205v12000f9jyltb78CF_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0233112000f9ivqwp4043_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236d12000f9ive4b9421_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232s12000f9j0j0d7904_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234412000f9jmykhE367_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232412000f9j1unjF141_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-27', '花园双床房', '双床房', '家庭亲子', 266, 0, 3, 9, '["前台服务","客房服务","整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度'),
('68027b02e3c98b094176591a', '升级住了红棉双床房，房间很大，送的迎宾点心很精致。酒店的环境非常好，玩携程铂金的行政酒廊在30楼旋转餐厅，早餐非常丰富，下午有点心水果和饮料。行政酒廊的Carrie是印度人，中文讲得很好，也非常热情。', '["https://dimg04.c-ctrip.com/images/0232t224x8vufbnce2813_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x224x8vuegeyf3D9E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234b224x8vuen1a2FABE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230s224x8vuep9bn4FC1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231r224x8vued9qr8061_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230h224x8vuecxd03E63_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234b224x8vudnycr89FF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233d224x8vueaib31500_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-05', '花园双床房', '双床房', '家庭亲子', 100, 1, 1, 8, '["餐饮设施","整体满意度","房间设施"]'::jsonb, '餐饮设施', '整体满意度', '房间设施'),
('68027b02e3c98b094176591b', '各方面都不错，有很多打卡点！大堂壁画和中国风的文化装饰值得体验！更值得惊艳的是藏在酒店里的博物馆！令本土广州人回忆了一把！', '["https://dimg04.c-ctrip.com/images/0230r12000fa87mhq07BB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236412000fa87t0w1FC2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236q12000fa87vbcF154_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-28', '花园双床房', '双床房', '朋友出游', 61, 0, 4, 7, '["公共设施","整体满意度"]'::jsonb, '公共设施', '整体满意度', NULL),
('68027b02e3c98b094176591c', '十一假期在花园酒店度过了两个晚上，我们一家都觉得很满意，以后有机会还会继续入住。', '["https://dimg04.c-ctrip.com/images/0230512000fyhn74iD916_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r12000fyiqmme15CD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230y12000fyivqajF1F7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000fyian0sBEF4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236h12000fyirh7fA5C1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x12000fyhn74m92FC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-04', '城央绿意双床房', '双床房', '家庭亲子', 40, 0, 19, 5, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027b02e3c98b094176591d', '服务满分，酒店活动送的小羊很可爱，自带的花园很漂亮，早餐也不错。掉了一根电源线在酒店马上联系我快递过来，体验感很棒。', '["https://dimg04.c-ctrip.com/images/0231l12000fc4xnph9088_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230s12000fc4sdj84089_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230512000fc51yo33BEF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231312000fc52rnx3E65_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-01', '红棉双床套房', '套房', '朋友出游', 58, 0, 12, 8, '["前台服务","整体满意度","餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施'),
('68027b02e3c98b094176591e', '房间很干净不错，床非常柔软舒适，整个酒店的人员服务非常到位（点名echo哦！），不愧是白金五星酒店，感觉服务人员比宾客还要多！', '["https://dimg04.c-ctrip.com/images/0230x12000f8x73tqDCE9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232a12000f8x8eid6BF8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235s12000f8x3a0yAE0F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234912000f8xadqwD2D8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231w12000f8x9q0b6EEE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-25', '花园大床房', '大床房', '情侣出游', 63, 0, 13, 7, '["整体满意度","房间设施","卫生状况"]'::jsonb, '整体满意度', '房间设施', '卫生状况'),
('68027b02e3c98b094176591f', '服务：很体贴 虽然办理入住时有点麻烦 但后期都解决

卫生：很干净中午办理的入住 都能及时打扫干净

设施：已经是老牌的五星酒店了 以往我更偏向对于新的酒店 这次是朋友要来临时找的 起初还是有点担心 但入住过后发现很棒 所以说酒店设施各方面无论不关岁月长短 跟管理层很大关系 为你们点赞????
环境：如若有点不怎么喜欢的是花园那块 环境幽雅但就是太多网红了 想去休息逛逛一堆网红在拍拍', '["https://dimg04.c-ctrip.com/images/0233d12000en08i8o3ED3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235h12000en0kkxpA97F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234h12000en0n9v8BF8D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-01', '花园大床房', '大床房', '朋友出游', 193, 0, 5, 7, '["前台服务","卫生状况","整体满意度"]'::jsonb, '前台服务', '卫生状况', '整体满意度'),
('68027b02e3c98b0941765920', '酒店公共设施装修的很好，酒店工作人员非常礼貌、周到??，连按电梯都有专门服务，我们准备 中午十二点退房时，航司短信提示延误 2 个小时，酒店特意安排我们可以延迟退房，这个太贴心了??????。但是缺点还是要说的，客房内部装修有点老，希望酒店能够将客房内部装修再提升下，以后再来还会选择入住。', '["https://dimg04.c-ctrip.com/images/0235t12000en2x7fp4962_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231j12000en36zfx31F4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231c12000en2xglqBEB6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-07-01', '花园双床房', '双床房', '家庭亲子', 145, 2, 10, 8, '["前台服务","公共设施","房间设施"]'::jsonb, '前台服务', '公共设施', '房间设施'),
('68027b02e3c98b0941765921', '酒店大堂富丽堂皇，服务宾至如归，有人主动帮忙提行李，开门，连电梯口也有服务员帮忙按电梯，前台的小姐姐isabella不仅人漂亮热情服务周到，而且还帮我升级了房间，太开心啦！以后过来旅游还会住这家酒店的。', '["https://dimg04.c-ctrip.com/images/0233t12000erfil4v9C0C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232912000erfh7lr543E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234g12000erfeob6EA21_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-12', '花园大床房', '大床房', '独自旅行', 101, 0, 13, 9, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027b0de3c98b0941765922', '前台小姐姐Viria人超nice，看到小朋友免费升级了房间还赠送了小朋友的早餐，房间也很干净整洁大气，花园酒店博物馆也很有意思，酒店充满中国传统文化和西方文化元素的完美融合，金光闪闪的太豪了，还有很多好吃的餐厅，很棒！', '["https://dimg04.c-ctrip.com/images/0230r12000emp86zr8427_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233112000emp794a7E92_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232k12000emp8ig8B659_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232d12000emp003p49B2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236112000emp4axfF0A7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231n12000emp86zt6068_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-30', '花园大床房', '大床房', '家庭亲子', 109, 0, 5, 9, '["前台服务","整体满意度","卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况'),
('68027b0de3c98b0941765923', '床垫很舒适，房间也很安静！入住过很多次了，很多房型都住过，每次去体验感都非常棒！下次还会选择推荐！', '["https://dimg04.c-ctrip.com/images/0233512000fk4gbuh0010_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-14', '花园双床房', '双床房', '家庭亲子', 49, 0, 4, 6, '["房间设施","安静程度","整体满意度"]'::jsonb, '房间设施', '安静程度', '整体满意度'),
('68027b0de3c98b0941765924', '3楼的旋转餐厅是亮点，每次出差我都住花园酒店，接待都是外籍加英文服务 非常国际化，老牌广州高端酒店，周边餐馆也很多', '["https://dimg04.c-ctrip.com/images/0232q224x8w7b7busA518_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230d224x8w78d33j0CDB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-03', '花园大床房', '大床房', '商务出差', 57, 0, 46, 7, '["餐饮设施","前台服务","周边配套"]'::jsonb, '餐饮设施', '前台服务', '周边配套'),
('68027b0de3c98b0941765925', '这次入住广州花园酒店体验超棒！必须夸夸前台的Rem。从踏入酒店的那一刻起，Rem就热情相迎，脸上洋溢着真诚的笑容，瞬间驱散了旅途的疲惫。办理入住时，他业务非常熟练，快速又高效地处理好了各项手续，还耐心解答我各种问题，给出游玩和用餐建议。Rem用专业与热忱诠释优质服务，让我有宾至如归之感，下次还选广州花园酒店 ，也期待再遇Rem ！', '["https://dimg04.c-ctrip.com/images/0233e12000j7rmks94254_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-21', '红棉大床套房', '套房', '情侣出游', 166, 0, 3, 9, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027b0de3c98b0941765926', '房间非常干净。特别是前台小姐姐吴灵玲的服务非常令我感到满意??，让我体会到宾至如归的感觉。给她点个赞！', '["https://dimg04.c-ctrip.com/images/0231512000fn5m8c67212_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-19', '花园大床房', '大床房', '商务出差', 51, 0, 1, 7, '["前台服务","卫生状况"]'::jsonb, '前台服务', '卫生状况', NULL),
('68027b0de3c98b0941765927', '之前看评价，说有什么霉味，心中有些许忐忑，结果到达第一天，踏进酒店的第一步就消除了所有顾虑，前台工作人员Vann（不知道名字是否正确？）帮忙升级了两间房，房间非常漂亮舒适，设施也很齐全，房间收拾的非常精致干净，工作人员也很友好，几乎每层楼都有工作人员帮忙按电梯，入住非常满意！后来因为航班取消，因为有老人，跟酒店商量，原房续住，工作人员很快速地帮忙协调解决，非常感谢！酒店的后花园环境很好，就是蚊子有点生猛，哈哈??', '["https://dimg04.c-ctrip.com/images/0232112000ekpgsi58683_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231612000ekph1tm6E6C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232x12000ekpgsi714F7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234q12000ekpgcapE923_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233312000ekpdmvl4626_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235o12000ekph2h89CA1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233z12000ekpdmvn2AAB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-25', '花园双床房', '双床房', '家庭亲子', 208, 0, 1, 9, '["前台服务","整体满意度","卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况'),
('68027b0de3c98b0941765928', '环境：酒店就在地铁口附近，很方便。酒店外部环境和内部装修陈列很讲究的。酒店外被绿色的植物包围和点缀，自然和谐；酒店内部随处可见的艺术品和讲究的装修设计，更让我对这家酒店有了新的认识。
设施：虽然开业很久，但是维护很好，根本不像其他老酒店一样，用陈旧的设施和老气装修来体现酒店“年代”和“经典”。各种设施设备配套很完善，不过还是有一点意外房间客厅电视屏幕有问题，希望及时检查维修；房间衣柜门开关的凹槽位置太锋利了，很容易划破手。
服务：从大堂的迎宾，到电梯口的员工，让这份服务从进入酒店就开始了，感觉无处不在。但是，好像去早了没房间，规定必须两点入住，无论是节假日还是工作日，去早了就要被 upsell ，虽然没多少钱，但是好像别人替我已经做好了选择。已经有点累了，还是加钱升级了，入住后才看到别人的会员金卡原来可以免费升级。
其他：早餐选择比较多，旋转餐厅景色也很好。
总的来说我很建议外地来广州的朋友去体验一下，感受来说比万豪希尔顿凯悦不一样，纯住宿角度来说也比白天鹅更推荐。', '["https://dimg04.c-ctrip.com/images/0232312000ekudkvk5E46_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235o12000eku8yjgF0C4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236912000eku4txn1F84_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230812000ekub8wyA9D7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235412000eku9ge3E2D9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230b12000ekudapd2DFA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232n12000eku2mtq5422_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231012000eku9o6g75EB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.6, 4, '2024-06-26', '花园大床房', '大床房', '独自旅行', 439, 0, 11, 9, '["交通便利性","房间设施","整体满意度"]'::jsonb, '交通便利性', '房间设施', '整体满意度'),
('68027b0de3c98b0941765929', '家庭出游，订的套餐，服务非常好，提前打电话准备好房间，提醒天气情况。早餐偏西式，选择在瀑布餐厅，餐后后花园散散步，很惬意。', '["https://dimg04.c-ctrip.com/images/0231s12000f7i587dBE7C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230z12000f7itxdi9846_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233n12000f7ivra5FBA2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-22', '花园双床房', '双床房', '家庭亲子', 61, 0, 2, 7, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('68027b0de3c98b094176592a', '广州有点热，客房服务很贴心多准备了饮用水。第一天看演唱会，第二天出去玩原本回来想问客房多要几瓶水的，没想到都准备好了，非常满意。酒店很漂亮，出行便捷，门口就有地铁站。', '["https://dimg04.c-ctrip.com/images/0237412000eunv3f800FB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234312000eunz5zb0C01_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233912000eunwhznEFAB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232g12000euo6lad144E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-21', '红棉双床套房', '套房', '朋友出游', 83, 0, 11, 8, '["客房服务","交通便利性","整体满意度"]'::jsonb, '客房服务', '交通便利性', '整体满意度'),
('68027b0de3c98b094176592b', '在预定前就了解到花园酒店的背景，也考虑到酒店因为装修比较老旧可能会有一些体验上的不足。但实际入住后觉得一直被惊喜到。酒店迎宾很体贴，能看到我（其实并未主动提出）的特殊入住需求，也给了很多实用建议。房间虽然不大，也没有智能马桶，但对我提出要除湿机马上就能响应。酒店的早餐很惊艳，虽说是网红餐厅但并没有因为客人众多而服务有任何缺失，其他餐厅预定也很方便。一层的花园人非常少，吃完早餐去溜达一下很悠闲。酒店位置也非常便利，出门就是地铁，周围都是餐厅，不想出门就订外卖，外卖柜位置虽然隐秘但知道在哪里后就挺好找的。', '["https://dimg04.c-ctrip.com/images/0234j12000emsnbm08233_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233412000emslgbm2CE3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231s12000emscou3CCA6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-06-30', '花园大床房', '大床房', '独自旅行', 253, 0, 2, 9, '["前台服务","餐饮设施","交通便利性"]'::jsonb, '前台服务', '餐饮设施', '交通便利性'),
('68027b17e3c98b094176592c', '非常好的老牌五星级大酒店，前台接待服务非常热情，房间干净整洁。离地铁站非常近出行非常便捷，小孩在游泳池游泳体验非常好。', '["https://dimg04.c-ctrip.com/images/0232d12000g7u1v943257_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233a12000g7tlj8mBC29_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233o12000g7u8v9p17EA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-19', '花园双床房', '双床房', '家庭亲子', 59, 0, 5, 7, '["前台服务","交通便利性","卫生状况"]'::jsonb, '前台服务', '交通便利性', '卫生状况'),
('68027b17e3c98b094176592d', '挺不错的，下次还会住这里??', '["https://dimg04.c-ctrip.com/images/0235k12000grzn7cf0925_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233812000grzog1p7B7F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236n12000gryr2u83B33_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-11-20', '花园双床房', '双床房', '朋友出游', 14, 0, 2, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
